/** name (lowercase) → canonical (lowest) code. Built once. */
const NAME_TO_CODE = (() => {
  const m = new Map();
  REGION_NAMES.forEach((name, code) => { if (!m.has(name)) m.set(name, code); });
  return m;
})();

/**
 * The single region name for a code.
 * @param {number} code  integer in [0,192)
 * @returns {string|null}
 */
export function regionName(code) {
  return isValidCellId(code) ? REGION_NAMES[code] : null;
}

/**
 * Back-compat shim: the region's name as a one-element array. Each region now
 * has exactly one name — prefer {@link regionName}. @deprecated
 * @param {number} code
 * @returns {[string]|null}
 */
export function regionNames(code) {
  return isValidCellId(code) ? [REGION_NAMES[code]] : null;
}

/**
 * Region code for a region name (case-insensitive). For a name that spans
 * adjacent cells, returns the canonical (lowest) code.
 * @param {string} name
 * @returns {number|null}
 */
export function regionCode(name) {
  if (typeof name !== 'string') return null;
  const code = NAME_TO_CODE.get(name.trim().toLowerCase());
  return code === undefined ? null : code;
}

/**
 * Resolve a region token — a NAME or a numeric code — to its 8-bit code.
 * Accepts 'useast', 'USEAST', '0x89', '137', or 137. A multi-cell name resolves
 * to its canonical (lowest) code.
 * @param {string|number} token
 * @returns {number|null}
 */
export function resolveRegion(token) {
  if (typeof token === 'number') return isValidCellId(token) ? token : null;
  if (typeof token !== 'string') return null;
  const t = token.trim();
  const byName = regionCode(t);
  if (byName !== null) return byName;
  const n = /^0x[0-9a-f]+$/i.test(t) ? parseInt(t, 16)
          : /^\d+$/.test(t)          ? parseInt(t, 10)
          : NaN;
  return isValidCellId(n) ? n : null;
}

/**
 * The region name for a (lat,lng) coordinate.
 * @param {number} lat
 * @param {number} lng
 * @returns {string}
 */
export function regionNameForLatLng(lat, lng) {
  return REGION_NAMES[geoCellId(lat, lng, 8)];
}

if (REGION_NAMES.length !== S2_CELL_COUNT) {
  throw new Error(
    `region-names.js: have ${REGION_NAMES.length} regions, expected ${S2_CELL_COUNT}`);
}
